import React, { useEffect, useState } from "react";
import { Box, Typography, Paper, CircularProgress, Alert, Button } from "@mui/material";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

const API = process.env.REACT_APP_API_URL || "http://localhost:5000";

const CaptainDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [captain, setCaptain] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const token = localStorage.getItem("token");

  const fetchCaptain = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API}/api/admin/captain/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setCaptain(res.data);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to fetch captain details");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCaptain();
  }, [id]);

  if (loading) return <CircularProgress />;
  if (error) return <Alert severity="error">{error}</Alert>;
  if (!captain) return null;

  return (
    <Box p={4}>
      <Button onClick={() => navigate(-1)}>Back</Button>
      <Typography variant="h4" mb={2}>{captain.fullName}</Typography>
      <Paper sx={{ p: 3 }}>
        <Typography><b>Email:</b> {captain.email}</Typography>
        <Typography><b>Mobile:</b> {captain.mobile}</Typography>
        <Typography><b>Status:</b> {captain.status}</Typography>
        <Typography><b>Documents:</b></Typography>
        <Box>
          {captain.documents?.length > 0 ? (
            captain.documents.map((doc, i) => (
              <Box key={i}>
                <a href={doc.url} target="_blank" rel="noreferrer">{doc.name}</a>
              </Box>
            ))
          ) : (
            <Typography>No documents uploaded</Typography>
          )}
        </Box>
      </Paper>
    </Box>
  );
};

export default CaptainDetails;
